class Solution:
    def findSmallestSetOfVertices(self, n, edges):
        adj = [[] for _ in range(n)]
        for u, v in edges:
            adj[u].append(v)
        reached_by_other = [False] * n
        for start in range(n):
            visited = [False] * n
            visited[start] = True
            stack = [start]
            while stack:
                cur = stack.pop()
                for nxt in adj[cur]:
                    if not visited[nxt]:
                        visited[nxt] = True
                        reached_by_other[nxt] = True
                        stack.append(nxt)
        return [v for v in range(n) if not reached_by_other[v]]

