var findSmallestSetOfVertices = function(n, edges) {
    const indegree = new Array(n).fill(0);
    for (const edge of edges) {
        indegree[edge[1]] += 1;
    }
    const res = [];
    for (let v = 0; v < n; v++) {
        if (indegree[v] === 0) res.push(v);
    }
    return res;
};
